// Enviar conversion event a Meta Conversions API
// Referencia: n8n/lib/meta_capi.js
const crypto = require('crypto');

const clickRow = $('Buscar CTWA sin Correlacionar').first().json;
const oppRow   = $('Oportunidad Ganada (Won)?').first().json;
const pixelId  = $env.META_PIXEL_ID;        // Variable adicional requerida
const token    = $env.META_CLOUD_API_TOKEN;

if (!pixelId || !token) {
  // Sin pixel configurado, no enviar CAPI pero no fallar
  return [{ json: { _capi_skip: true, reason: 'META_PIXEL_ID no configurado' } }];
}

// Event ID deterministico para deduplicacion
const event_id = crypto.createHash('sha256').update(clickRow.ctwa_clid + 'Purchase').digest('hex');

// Hash phone para Meta
const hashPhone = clickRow.phone
  ? crypto.createHash('sha256').update(clickRow.phone.replace(/\s/g, '')).digest('hex')
  : null;

const event_time = Math.floor(Date.now() / 1000);

const payload = {
  data: [{
    event_name:     'Purchase',
    event_time,
    event_id,
    action_source:  'business_messaging',
    messaging_channel: 'whatsapp',
    user_data: Object.assign({ ctwa_clid: clickRow.ctwa_clid }, hashPhone ? { ph: [hashPhone] } : {}),
    custom_data: {
      value:    oppRow.monetary_value || 0,
      currency: oppRow.currency || 'COP'
    }
  }]
};

const url = `https://graph.facebook.com/v18.0/${pixelId}/events?access_token=${encodeURIComponent(token)}`;

let response;
try {
  const resp = await fetch(url, {
    method:  'POST',
    headers: { 'Content-Type': 'application/json' },
    body:    JSON.stringify(payload)
  });
  response = await resp.json();
  if (!resp.ok) throw new Error('Meta CAPI HTTP ' + resp.status);
} catch (err) {
  // Loguear error pero no romper el flujo
  return [{ json: { _capi_skip: true, reason: err.message } }];
}

return [{ json: {
  event_id,
  capi_payload: payload,
  capi_response: response,
  opportunity_id: oppRow.opportunity_id,
  ctwa_clid: clickRow.ctwa_clid
} }];
